3. 基本数据类型

3.1 数值型（Numeric）
# 数值型数据
num1 &lt;- 10
num2 &lt;- 3.14
num_vector &lt;- c(1, 2, 3, 4, 5)


# 查看类型
class(num1)
## [1] &quot;numeric&quot;
typeof(num1)
## [1] &quot;double&quot;
# 基本运算
sum_result &lt;- num1 + num2
prod_result &lt;- num1 * num2
sqrt_result &lt;- sqrt(num1)


3.2 字符型（Character）
# 字符型数据
char1 &lt;- &quot;Hello, R!&quot;
char2 &lt;- &#39;R语言&#39;
char_vector &lt;- c(&quot;apple&quot;, &quot;banana&quot;, &quot;cherry&quot;)

# 字符串操作
paste(&quot;Hello&quot;, &quot;World&quot;, sep = &quot; &quot;)
## [1] &quot;Hello World&quot;
nchar(&quot;R Programming&quot;)
## [1] 13
toupper(&quot;hello&quot;)
## [1] &quot;HELLO&quot;
tolower(&quot;WORLD&quot;)
## [1] &quot;world&quot;


3.3 逻辑型（Logical）
# 逻辑型数据
logical1 &lt;- TRUE
logical2 &lt;- FALSE
logical_vector &lt;- c(TRUE, FALSE, TRUE, FALSE)

# 逻辑运算
5 &gt; 3
## [1] TRUE
5 == 5
## [1] TRUE
5 != 3
## [1] TRUE
TRUE &amp; FALSE
## [1] FALSE
TRUE | FALSE
## [1] TRUE


3.4 因子型（Factor）
# 创建因子
gender &lt;- factor(c(&quot;Male&quot;, &quot;Female&quot;, &quot;Male&quot;, &quot;Female&quot;, &quot;Male&quot;))
levels(gender)
## [1] &quot;Female&quot; &quot;Male&quot;
unique(gender)
## [1] Male   Female
## Levels: Female Male
table(gender)
## gender
## Female   Male 
##      2      3



