6. 数据处理（使用dplyr）
# 加载dplyr包
library(dplyr)

# 创建示例数据
set.seed(123)  # 设置随机种子，确保结果可重复
sales_data &lt;- data.frame(
  Month = rep(month.name[1:6], each = 5),
  Product = rep(c(&quot;A&quot;, &quot;B&quot;, &quot;C&quot;, &quot;D&quot;, &quot;E&quot;), times = 6),
  Sales = round(rnorm(30, mean = 1000, sd = 200), 0),
  Region = rep(c(&quot;North&quot;, &quot;South&quot;), each = 15)
)

# 查看数据
head(sales_data)
##      Month Product Sales Region
## 1  January       A   888  North
## 2  January       B   954  North
## 3  January       C  1312  North
## 4  January       D  1014  North
## 5  January       E  1026  North
## 6 February       A  1343  North
# 1. 筛选数据
filtered_data &lt;- sales_data %&gt;%
  filter(Sales &gt; 1000, Region == &quot;North&quot;)

# 2. 选择列
selected_data &lt;- sales_data %&gt;%
  select(Month, Product, Sales)

# 3. 排序
sorted_data &lt;- sales_data %&gt;%
  arrange(desc(Sales))

# 4. 创建新列
transformed_data &lt;- sales_data %&gt;%
  mutate(Sales_Group = ifelse(Sales &gt; 1000, &quot;High&quot;, &quot;Low&quot;),
         Log_Sales = log(Sales))

# 5. 分组汇总
summary_data &lt;- sales_data %&gt;%
  group_by(Region, Product) %&gt;%
  summarise(
    Total_Sales = sum(Sales),
    Avg_Sales = mean(Sales),
    Count = n(),
    .groups = &#39;drop&#39;
  )

# 6. 连接数据
# 创建另一个数据框
price_data &lt;- data.frame(
  Product = c(&quot;A&quot;, &quot;B&quot;, &quot;C&quot;, &quot;D&quot;, &quot;E&quot;),
  Price = c(50, 60, 45, 70, 55)
)

# 内连接
joined_data &lt;- sales_data %&gt;%
  inner_join(price_data, by = &quot;Product&quot;)

