8.2 使用maps包绘制基础地图
# 1. 世界地图
#cat(&quot;1. 绘制世界地图:\n&quot;)
world_map &lt;- map_data(&quot;world&quot;)
ggplot() +
  geom_polygon(data = world_map, 
               aes(x = long, y = lat, group = group),
               fill = &quot;lightblue&quot;, color = &quot;black&quot;, alpha = 0.7) +
  coord_fixed(1.3) +
  labs(title = &quot;世界地图&quot;, 
       caption = &quot;使用maps包绘制&quot;) +
  theme_minimal() +
  theme(axis.text = element_blank(),
        axis.title = element_blank(),
        panel.grid = element_blank())

# 2. 中国地图
#cat(&quot;\n2. 绘制中国地图:\n&quot;)
china_map &lt;- map_data(&quot;china&quot;)
ggplot() +
  geom_polygon(data = china_map, 
               aes(x = long, y = lat, group = group),
               fill = &quot;#FFCCCC&quot;, color = &quot;#990000&quot;, alpha = 0.8) +
  coord_fixed(1.3) +
  labs(title = &quot;中国地图&quot;, 
       caption = &quot;使用maps包绘制&quot;) +
  theme_minimal() +
  theme(axis.text = element_blank(),
        axis.title = element_blank(),
        panel.grid = element_blank())



8.3 使用ggplot2绘制美国各州地图
# 创建美国各州数据
#cat(&quot;3. 美国各州人口数据地图:\n&quot;)

# 获取美国地图数据
usa_map &lt;- map_data(&quot;state&quot;)

# 创建模拟的人口数据
set.seed(123)
state_pop &lt;- data.frame(
  region = tolower(state.name),
  population = sample(1:100, 50, replace = TRUE),
  income = rnorm(50, mean = 50000, sd = 10000)
)

# 合并地图数据和人口数据
usa_map_data &lt;- merge(usa_map, state_pop, 
                      by.x = &quot;region&quot;, by.y = &quot;region&quot;, 
                      all.x = TRUE)

# 绘制人口分布地图
p1 &lt;- ggplot(usa_map_data) +
  geom_polygon(aes(x = long, y = lat, group = group, fill = population),
               color = &quot;white&quot;, size = 0.2) +
  scale_fill_gradient(low = &quot;lightblue&quot;, high = &quot;darkblue&quot;, 
                     name = &quot;人口(百万)&quot;) +
  coord_fixed(1.3) +
  labs(title = &quot;美国各州人口分布图&quot;,
       subtitle = &quot;颜色深浅表示人口数量&quot;) +
  theme_void() +
  theme(plot.title = element_text(hjust = 0.5, face = &quot;bold&quot;),
        legend.position = &quot;right&quot;)

# 绘制收入分布地图
p2 &lt;- ggplot(usa_map_data) +
  geom_polygon(aes(x = long, y = lat, group = group, fill = income),
               color = &quot;white&quot;, size = 0.2) +
  scale_fill_gradient(low = &quot;yellow&quot;, high = &quot;red&quot;, 
                     name = &quot;平均收入($)&quot;) +
  coord_fixed(1.3) +
  labs(title = &quot;美国各州平均收入分布图&quot;,
       subtitle = &quot;颜色表示平均收入水平&quot;) +
  theme_void() +
  theme(plot.title = element_text(hjust = 0.5, face = &quot;bold&quot;),
        legend.position = &quot;right&quot;)

# 显示两个地图
library(patchwork)
p1 + p2



