8.5 使用leaflet创建交互式地图
#cat(&quot;5. 创建交互式地图:\n&quot;)

# 创建模拟的中国城市数据
set.seed(2026)
china_cities &lt;- data.frame(
  city = c(&quot;北京&quot;, &quot;上海&quot;, &quot;广州&quot;, &quot;深圳&quot;, &quot;成都&quot;, &quot;武汉&quot;, &quot;西安&quot;, &quot;杭州&quot;),
  lat = c(39.9042, 31.2304, 23.1291, 22.5431, 30.5728, 30.5928, 34.3416, 30.2741),
  lng = c(116.4074, 121.4737, 113.2644, 114.0579, 104.0668, 114.3055, 108.9398, 120.1551),
  population = c(2154, 2428, 1530, 1768, 1658, 1121, 1295, 1194),  # 万人
  gdp = c(40269, 44653, 28232, 30665, 19917, 17716, 10020, 18753)  # 亿元
)

# 创建leaflet交互式地图
leaflet_map &lt;- leaflet(china_cities) %&gt;%
  addTiles() %&gt;%  # 添加默认地图图层
  addCircleMarkers(
    lng = ~lng, 
    lat = ~lat,
    radius = ~population/500,  # 半径与人口成正比
    color = &quot;red&quot;,
    fillColor = &quot;orange&quot;,
    fillOpacity = 0.7,
    popup = ~paste(
      &quot;&lt;b&gt;城市:&lt;/b&gt; &quot;, city, &quot;&lt;br&gt;&quot;,
      &quot;&lt;b&gt;人口:&lt;/b&gt; &quot;, format(population, big.mark = &quot;,&quot;), &quot;万人&lt;br&gt;&quot;,
      &quot;&lt;b&gt;GDP:&lt;/b&gt; &quot;, format(gdp, big.mark = &quot;,&quot;), &quot;亿元&quot;
    ),
    label = ~city
  ) %&gt;%
  addControl(
    &quot;&lt;h4&gt;中国主要城市数据&lt;/h4&gt;
    &lt;p&gt;圆圈大小表示人口规模&lt;br&gt;
    点击查看详细信息&lt;/p&gt;&quot;,
    position = &quot;topright&quot;
  )

# 注意：在R Markdown中，leaflet地图可能需要设置正确的输出
