9.2 创建基础动画
#cat(&quot;1. 创建简单的时间序列动画:\n&quot;)

# 创建模拟的时间序列数据
set.seed(2026)
time_data &lt;- data.frame(
  time = rep(1:20, each = 10),
  group = rep(LETTERS[1:10], 20),
  value = cumsum(rnorm(200))
) %&gt;%
  group_by(time) %&gt;%
  mutate(rank = rank(-value),
         value_rel = value/value[rank==1],
         label = paste0(&quot; &quot;, round(value,1))) %&gt;%
  ungroup()

# 创建条形竞赛图动画
anim_bar &lt;- ggplot(time_data, aes(x = rank, y = value, group = group)) +
  geom_tile(aes(y = value/2, height = value, fill = group), 
            width = 0.9, alpha = 0.8) +
  geom_text(aes(y = 0, label = paste(group, &quot; &quot;)), vjust = 0.2, hjust = 1) +
  geom_text(aes(label = label, hjust = 0)) +
  coord_flip(clip = &quot;off&quot;, expand = FALSE) +
  scale_x_reverse() +
  scale_fill_viridis_d(option = &quot;plasma&quot;) +
  labs(title = &#39;时间: {closest_state}&#39;,
       x = &quot;&quot;, y = &quot;数值&quot;) +
  theme_minimal() +
  theme(plot.title = element_text(hjust = 0.5, size = 22),
        axis.line = element_blank(),
        axis.text.x = element_blank(),
        axis.text.y = element_blank(),
        axis.ticks = element_blank(),
        axis.title.x = element_blank(),
        axis.title.y = element_blank(),
        legend.position = &quot;none&quot;,
        panel.grid = element_blank()) +
  transition_states(time, transition_length = 2, state_length = 1) +
  ease_aes(&#39;cubic-in-out&#39;)

anim_bar

