9.6 创建地图动画
#cat(&quot;5. 创建地图动画（展示地理数据随时间变化）:\n&quot;)

# 创建模拟的全球气温变化数据
set.seed(2026)
years &lt;- 2000:2010
countries &lt;- unique(world_map$region)

# 创建模拟数据
temp_data &lt;- expand.grid(
  year = years,
  region = sample(countries, 30)  # 随机选择30个国家
) %&gt;%
  mutate(
    temperature = 15 + 0.1*(year - 2000) + rnorm(n(), sd = 2),
    region = as.character(region)
  )

# 合并地图数据
world_map_data &lt;- world_map %&gt;%
  left_join(temp_data, by = c(&quot;region&quot;))
