9.7 创建3D散点图动画
#cat(&quot;6. 创建3D散点图动画:\n&quot;)

# 使用plotly创建3D动画
# install.packages(&quot;plotly&quot;)
library(plotly)
## 
## 载入程序包：&#39;plotly&#39;
## The following object is masked from &#39;package:ggplot2&#39;:
## 
##     last_plot
## The following object is masked from &#39;package:stats&#39;:
## 
##     filter
## The following object is masked from &#39;package:graphics&#39;:
## 
##     layout
library(gapminder)

# 创建3D散点图
p3d &lt;- gapminder %&gt;%
  plot_ly(
    x = ~gdpPercap,
    y = ~lifeExp,
    z = ~pop,
    color = ~continent,
    frame = ~year,
    text = ~country,
    hoverinfo = &quot;text&quot;,
    type = &#39;scatter3d&#39;,
    mode = &#39;markers&#39;,
    marker = list(size = ~pop/10000000, sizemode = &#39;diameter&#39;)
  ) %&gt;%
  layout(
    title = &quot;3D Gapminder动画: 人均GDP vs 预期寿命 vs 人口&quot;,
    scene = list(
      xaxis = list(title = &quot;人均GDP&quot;, type = &quot;log&quot;),
      yaxis = list(title = &quot;预期寿命&quot;),
      zaxis = list(title = &quot;人口&quot;, type = &quot;log&quot;)
    )
  ) %&gt;%
  animation_opts(frame = 100, transition = 50, redraw = TRUE) %&gt;%
  animation_slider(currentvalue = list(prefix = &quot;年份: &quot;))

# 注意：在R Markdown中，plotly动画需要适当的输出设置
# 如果是HTML输出，可以直接显示
