9.8 综合案例：COVID-19数据地图动画
#cat(&quot;8. 综合案例: COVID-19数据地图动画\n&quot;)

# 模拟COVID-19数据
set.seed(2026)
covid_dates &lt;- seq.Date(as.Date(&quot;2026-01-01&quot;), as.Date(&quot;2026-01-31&quot;), by = &quot;day&quot;)
countries &lt;- c(&quot;USA&quot;, &quot;China&quot;, &quot;India&quot;, &quot;Brazil&quot;, &quot;Russia&quot;, &quot;UK&quot;, &quot;France&quot;, &quot;Germany&quot;, &quot;Japan&quot;, &quot;South Korea&quot;)

# 创建模拟数据
covid_data &lt;- expand.grid(
  date = covid_dates,
  country = countries
) %&gt;%
  mutate(
    cases = sample(100:10000, n(), replace = TRUE),
    deaths = round(cases * runif(n(), 0.01, 0.05))
  )

# 创建国家名称映射（用于地图）
country_mapping &lt;- data.frame(
  country = countries,
  region = c(&quot;USA&quot;, &quot;China&quot;, &quot;India&quot;, &quot;Brazil&quot;, &quot;Russia&quot;, &quot;UK&quot;, &quot;France&quot;, &quot;Germany&quot;, &quot;Japan&quot;, &quot;South Korea&quot;)
)

# 获取世界地图数据
world_covid &lt;- world_map %&gt;%
  left_join(country_mapping, by = &quot;region&quot;) %&gt;%
  left_join(covid_data, by = &quot;country&quot;)
## Warning in left_join(., covid_data, by = &quot;country&quot;): Detected an unexpected many-to-many relationship between `x` and `y`.
## i Row 11920 of `x` matches multiple rows in `y`.
## i Row 94 of `y` matches multiple rows in `x`.
## i If a many-to-many relationship is expected, set `relationship =
##   &quot;many-to-many&quot;` to silence this warning.
# 创建COVID-19地图动画
covid_anim &lt;- ggplot(world_covid) +
  geom_polygon(aes(x = long, y = lat, group = group, fill = cases),
               color = &quot;white&quot;, size = 0.1) +
  scale_fill_gradient(low = &quot;yellow&quot;, high = &quot;red&quot;, 
                     trans = &quot;log10&quot;,
                     name = &quot;确诊病例数&quot;,
                     na.value = &quot;gray90&quot;) +
  coord_fixed(1.3) +
  labs(title = &quot;COVID-19疫情地图: {closest_state}&quot;,
       subtitle = &quot;模拟数据展示&quot;,
       caption = &quot;数据来源: 模拟数据&quot;) +
  theme_void() +
  theme(plot.title = element_text(hjust = 0.5, face = &quot;bold&quot;, size = 16),
        plot.subtitle = element_text(hjust = 0.5, size = 12),
        legend.position = &quot;bottom&quot;) +
  transition_states(date, transition_length = 1, state_length = 2)

covid_anim
