10.2 flextable高级格式化
# 创建更复杂的表格
#cat(&quot;\n创建高级格式化表格:\n&quot;)

# 准备数据
detailed_table &lt;- mtcars %&gt;%
  select(mpg, cyl, hp, wt, am) %&gt;%
  mutate(
    am = ifelse(am == 0, &quot;自动&quot;, &quot;手动&quot;),
    mpg_category = cut(mpg,
                      breaks = c(0, 15, 20, 25, 35),
                      labels = c(&quot;差&quot;, &quot;中&quot;, &quot;良&quot;, &quot;优&quot;),
                      include.lowest = TRUE)
  ) %&gt;%
  arrange(desc(mpg))

# 创建flextable
advanced_ft &lt;- flextable(head(detailed_table, 10)) %&gt;%
  # 设置表格标题
  set_caption(&quot;汽车详细数据表（前10行）&quot;) %&gt;%

  # 设置主题
  theme_zebra(odd_header = &quot;#4A8BBD&quot;, even_header = &quot;#4A8BBD&quot;,
              odd_body = &quot;#E6F3FF&quot;, even_body = &quot;white&quot;) %&gt;%

  # 列格式设置
  set_header_labels(
    mpg = &quot;油耗\n(英里/加仑)&quot;,
    cyl = &quot;气缸数&quot;,
    hp = &quot;马力&quot;,
    wt = &quot;重量\n(1000磅)&quot;,
    am = &quot;变速箱&quot;,
    mpg_category = &quot;油耗评级&quot;
  ) %&gt;%

  # 数字格式化
  colformat_num(j = c(&quot;mpg&quot;, &quot;hp&quot;, &quot;wt&quot;),
                big.mark = &quot;&quot;, digits = 1) %&gt;%

  # 条件格式
  bg(j = &quot;mpg&quot;, 
     bg = &quot;#FFCCCC&quot;,  # 正确：使用颜色字符串
     part = &quot;body&quot;,
     i = ~ mpg &lt; 20) %&gt;%

  bg(j = &quot;mpg&quot;, 
     bg = &quot;#CCFFCC&quot;,
     part = &quot;body&quot;,
     i = ~ mpg &gt;= 25) %&gt;%

  # 添加脚注
  add_footer_lines(&quot;数据来源: mtcars内置数据集&quot;) %&gt;%
  italic(part = &quot;footer&quot;) %&gt;%
  color(color = &quot;gray50&quot;, part = &quot;footer&quot;) %&gt;%

  # 合并单元格
  merge_h(part = &quot;header&quot;) %&gt;%
  merge_v(part = &quot;header&quot;) %&gt;%

  # 设置边框
  border_outer(border = fp_border(color = &quot;#4A8BBD&quot;, width = 2)) %&gt;%
  border_inner_h(border = fp_border(color = &quot;gray80&quot;, width = 1)) %&gt;%
  border_inner_v(border = fp_border(color = &quot;gray80&quot;, width = 1)) %&gt;%

  # 自动调整列宽
  autofit() %&gt;%

  # 设置字体
  font(fontname = &quot;Arial&quot;, part = &quot;all&quot;) %&gt;%
  fontsize(size = 10, part = &quot;body&quot;) %&gt;%
  fontsize(size = 12, part = &quot;header&quot;) %&gt;%
  bold(part = &quot;header&quot;)

