#cat(&quot;\n创建分组汇总表格:\n&quot;)

# 创建分组汇总数据
group_summary &lt;- mtcars %&gt;%
  group_by(cyl, am) %&gt;%
  summarise(
    n = n(),
    mean_mpg = mean(mpg),
    sd_mpg = sd(mpg),
    mean_hp = mean(hp),
    sd_hp = sd(hp),
    mean_wt = mean(wt),
    sd_wt = sd(wt),
    .groups = &#39;drop&#39;
  ) %&gt;%
  mutate(
    am = ifelse(am == 0, &quot;自动变速箱&quot;, &quot;手动变速箱&quot;),
    across(where(is.numeric), round, 2)
  )

# 创建汇总表格
summary_ft &lt;- flextable(group_summary) %&gt;%
  set_caption(&quot;按气缸数和变速箱分组的汽车数据汇总&quot;) %&gt;%

  # 添加分组标题
  add_header_row(
    top = TRUE,
    values = c(&quot;&quot;, &quot;样本量&quot;, &quot;油耗 (mpg)&quot;, &quot;马力 (hp)&quot;, &quot;重量 (wt)&quot;),
    colwidths = c(2, 1, 2, 2, 2)
  ) %&gt;%

  # 设置子标题
  set_header_labels(
    cyl = &quot;气缸数&quot;,
    am = &quot;变速箱类型&quot;,
    n = &quot;数量&quot;,
    mean_mpg = &quot;均值&quot;,
    sd_mpg = &quot;标准差&quot;,
    mean_hp = &quot;均值&quot;,
    sd_hp = &quot;标准差&quot;,
    mean_wt = &quot;均值&quot;,
    sd_wt = &quot;标准差&quot;
  ) %&gt;%

  # 合并表头
  merge_h(part = &quot;header&quot;) %&gt;%
  merge_v(part = &quot;header&quot;) %&gt;%

  # 设置主题
  theme_box() %&gt;%

  # 设置对齐
  align(align = &quot;center&quot;, part = &quot;all&quot;) %&gt;%
  align(j = 1:2, align = &quot;left&quot;) %&gt;%

  # 设置边框
  border_outer(border = fp_border(width = 1.5)) %&gt;%
  border_inner_h(border = fp_border(width = 0.5)) %&gt;%
  border_inner_v(border = fp_border(width = 0.5)) %&gt;%

  # 设置背景色
  bg(i = ~ cyl == 4, bg = &quot;#E8F4F8&quot;, part = &quot;body&quot;) %&gt;%
  bg(i = ~ cyl == 6, bg = &quot;#F0F8E8&quot;, part = &quot;body&quot;) %&gt;%
  bg(i = ~ cyl == 8, bg = &quot;#F8E8E8&quot;, part = &quot;body&quot;) %&gt;%

  # 自动调整
  autofit() %&gt;%

  # 添加脚注
  add_footer_lines(c(&quot;* 数据基于mtcars内置数据集&quot;,
                     &quot;* 油耗单位为英里/加仑&quot;,
                     &quot;* 重量单位为1000磅&quot;)) %&gt;%
  italic(part = &quot;footer&quot;) %&gt;%
  fontsize(size = 9, part = &quot;footer&quot;)

