# 创建带默认参数的函数
calculate_bmi &lt;- function(weight, height, unit = &quot;metric&quot;) {
  if (unit == &quot;metric&quot;) {
    bmi &lt;- weight / (height^2)
  } else if (unit == &quot;imperial&quot;) {
    bmi &lt;- (weight / (height^2)) * 703
  } else {
    stop(&quot;单位必须是 &#39;metric&#39; 或 &#39;imperial&#39;&quot;)
  }

  # 分类
  category &lt;- cut(bmi, 
                  breaks = c(0, 18.5, 25, 30, Inf),
                  labels = c(&quot;体重过轻&quot;, &quot;正常&quot;, &quot;超重&quot;, &quot;肥胖&quot;),
                  right = FALSE)

  return(list(bmi = round(bmi, 2), category = category))
}

# 测试函数
